// Setup: npm install rxjs
import { interval, Subscription } from 'rxjs';

// Imagine this is a UI component class. It "mounts" via init() and "unmounts" via destroy().
class TickerWidget {
  private currentTick = 0;

  init() {
    // poll every second forever
    interval(1000).subscribe((n) => {
      this.currentTick = n;
      console.log('tick', n);
    });
  }

  destroy() {
    // teardown — but the subscription above is still running
  }
}

const w = new TickerWidget();
w.init();
setTimeout(() => w.destroy(), 3500);
// ticks keep logging after destroy() — leak.

// Setup: npm install rxjs
import { Observable } from 'rxjs';

declare function fetchUser(id: string): Observable<{ id: string; teamId: string }>;
declare function fetchTeam(teamId: string): Observable<{ id: string; name: string }>;

function loadUserTeam(userId: string, onResult: (team: { id: string; name: string }) => void) {
  fetchUser(userId).subscribe((user) => {
    fetchTeam(user.teamId).subscribe((team) => {
      onResult(team);
    });
  });
}

